solution_code:
#include <iostream>
#include <iomanip>

using Celsius    = double;
using Fahrenheit = double;

int main()
{
    Celsius c {};
    std::cin >> c;
    Fahrenheit f { c * 9.0 / 5.0 + 32.0 };
    std::cout << std::fixed << std::setprecision(1)
              << "Fahrenheit: " << f << '\n';
    return 0;
}

