#include <iostream>
#include <iomanip>

using Pixels = int;
using Inches = double;
using PPI    = double;

int main()
{
    Pixels px {};
    Inches diag {};
    std::cin >> px >> diag;

    // bug: diag is truncated to int before division, causing integer division
    int idiag = static_cast<int>(diag);
    PPI density = px / idiag;
    std::cout << std::fixed << std::setprecision(1)
              << "PPI: " << density << '\n';
    return 0;
}

